+          configPath: CONFIG_PATH_CLAWDBOT,
+          defaultModel: defaultLabel,
+          resolvedDefault: `${resolved.provider}/${resolved.model}`,
+          fallbacks,
+          aliases,
+          allowed,
+        },
+        null,
+        2,
+      ),
