+    return;
+  }
+
+  if (opts.plain) {
+    runtime.log(defaultLabel);
+    return;
+  }
+
+  runtime.log(info(`Config: ${CONFIG_PATH_CLAWDBOT}`));
+  runtime.log(`Default: ${defaultLabel}`);
+  runtime.log(
+    `Fallbacks (${fallbacks.length || 0}): ${fallbacks.join(", ") || "-"}`,
