+  runtime.log(
+    `Aliases (${Object.keys(aliases).length || 0}): ${
+      Object.keys(aliases).length
+        ? Object.entries(aliases)
+            .map(([alias, target]) => `${alias} -> ${target}`)
+            .join(", ")
+        : "-"
+    }`,
+  );
+  runtime.log(
